#include <stdio.h>
#include <math.h>

int minEatingSpeed(int* a, int n, int h) {
    int maxVal = a[0];
    for (int i = 1; i < n; i++) {
        if (a[i] > maxVal) {
            maxVal = a[i];
        }
    }

    int low = 1, high = maxVal;
    while (low < high) {
        int mid = (low + high) / 2;
        long long totalHours = 0;
        for (int i = 0; i < n; i++) {
            totalHours += (a[i] + mid - 1) / mid;
        }
        if (totalHours > h) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return low;
}

int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int h;
    scanf("%d", &h);
    printf("%d\n", minEatingSpeed(a, n, h));
    return 0;
}

