class Solution {
    // Function to calculate total hours for given speed
    calculateTotalHours(a, hourly) {
        let totalHours = 0;
        for (let pile of a) {
            // Add hours using ceil
            totalHours += Math.ceil(pile / hourly);
        }
        return totalHours;
    }

    // Function to find minimum eating speed
    minEatingSpeed(a, h) {
        // Find maximum pile size
        let maxVal = Math.max(...a);

        // Try every possible speed
        let low = 1, high = maxVal;
        while (low < high) {
            let mid = Math.floor((low + high) / 2);
            let hours = this.calculateTotalHours(a, mid);

            // If hours fit within h
            if (hours <= h) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }
}

